import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"61. Purchased Leave","description":"","frontmatter":{"title":"61. Purchased Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","wages","employment"]},"headers":[],"relativePath":"ebas/allied-health/leave/61-purchased-leave.md","filePath":"ebas/allied-health/leave/61-purchased-leave.md"}'),n={name:"ebas/allied-health/leave/61-purchased-leave.md"};function s(l,e,p,h,i,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_61-purchased-leave" tabindex="-1">61. Purchased Leave <a class="header-anchor" href="#_61-purchased-leave" aria-label="Permalink to &quot;61. Purchased Leave&quot;">​</a></h1><p>This clause 61 does not apply to casual Employees.</p><p><strong>61.1</strong> An Employee may apply to purchase up to 20 working days (pro-rated for part- time Employees) additional paid leave in a twelve-month period at ordinary pay. The Employer will not unreasonably withhold approval of an application to purchase leave by an Employee. The additional paid leave is purchased through salary deductions made over the whole year. The amount deducted will correspond with the amount of leave purchased.</p><p>Examples: 1. An Employee who purchases an additional four (4) weeks leave will be paid 48/52 or 92.31% of their ordinary pay throughout the relevant 12 month period. 2. An Employee who purchases an additional two (2) weeks leave will be paid 50/52 or 96.15% of their ordinary pay throughout the relevant 12 month period.</p><p><strong>61.2</strong> Purchased Leave may be taken in conjunction with other types of leave.</p><p><strong>61.3</strong> Purchased Leave must be used in the twelve-month period in which it is purchased. Purchased leave will be taken at a time that is mutually agreed between the Employer and the Employee, save that the Employer will not unreasonably refuse to agree to a request by the Employee to:</p><p><strong>(a)</strong> take purchased leave at a particular time; and/or</p><p><strong>(b)</strong> change when they take their purchased leave.</p><p><strong>61.4</strong> Once approval has been granted, the Employee may only vary or cancel the arrangement in extraordinary circumstances.</p><p><strong>61.5</strong> Where the:</p><p><strong>(a)</strong> arrangement has been varied or cancelled because of extraordinary circumstances;</p><p><strong>(b)</strong> Employee’s employment terminates; or</p><p><strong>(c)</strong> purchased leave has not been taken in the relevant 12-month period; the Employer will refund the amount of salary deducted in respect of any unused purchased leave as a lump sum. In the case of variation or cancellation, payment will be made no later than two (2) pay periods following notification of the variation or cancellation.</p><p><strong>61.6</strong> Where the Employee’s employment terminates and the amount of purchased leave taken exceeds the amount deducted, the Employer may deduct a sum equal to the negative balance from any remuneration payable to the Employee upon termination of employment.</p><p><strong>61.7</strong> Purchased leave:</p><p><strong>(a)</strong> counts as service for all purposes; and</p><p><strong>(b)</strong> is not annual leave.</p>',17)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
